import { Injectable } from '@angular/core';
import {HttpHeaders, HttpClient} from "@angular/common/http";
import {map, Observable} from "rxjs";

@Injectable({
  providedIn: 'root'
})
export class AwbService {

  private baseUrl: string;
  private bearerToken: string;
  constructor(private http: HttpClient) {
    this.baseUrl = "http://cs-v-albert.champ.aero";
    this.bearerToken = this.getBearerToken();
  }

  async getBearerToken(): Promise<void> {
    const url = this.baseUrl + ":8989/realms/neone/protocol/openid-connect/token";
    const payload = 'grant_type=client_credentials&client_id=neone-client';
    const headers = new HttpHeaders({
      'Content-Type': 'application/x-www-form-urlencoded',
      'Authorization': 'Basic bmVvbmUtY2xpZW50Omx4N1RoUzVhWWdnZHNNbTQyQlAzd01yVnFLbTlXcE5Z'
    });

    try {
      const response = await this.http.post<any>(url, payload, { headers }).toPromise();
      this.bearerToken = response.access_token;
    } catch (error) {
      console.error('Error fetching bearer token:', error);
      throw error; // Propagate the error
    }
  }

